private boolean testValidProtocol(Element el, Attribute attr, Set<Protocol> protocols) {
    // Check for null values
    if (el == null || attr == null || protocols == null) {
        return false;
    }

    String value = attr.getValue();
    boolean isCustomProtocol = false;

    // Check if the current value matches any custom protocol
    for (Protocol protocol : protocols) {
        String prot = protocol.toString() + ":";
        if (value.toLowerCase().startsWith(prot)) {
            isCustomProtocol = true;
            break;
        }
    }

    // Resolve to absolute URL only if it's not a custom protocol
    if (!isCustomProtocol && !preserveRelativeLinks) {
        value = el.absUrl(attr.getKey());
        attr.setValue(value);
    }

    // Recheck after potential resolution
    for (Protocol protocol : protocols) {
        String prot = protocol.toString() + ":";
        if (value.toLowerCase().startsWith(prot)) {
            return true;
        }
    }
    return false;
}

private boolean testValidProtocol(Element el, Attribute attr, Set<Protocol> protocols) {
    // try to resolve relative urls to abs, and optionally update the attribute so output html has abs.
    // rels without a baseuri get removed
    String value = attr.getValue();
    if (!preserveRelativeLinks && el.baseUri() != null) {
        String absValue = el.absUrl(attr.getKey());
        if (!absValue.isEmpty()) {
            value = absValue;
            attr.setValue(value);
        }
    }

    for (Protocol protocol : protocols) {
        String prot = protocol.toString() + ":";
        if (value.toLowerCase().startsWith(prot)) {
            return true;
        }
    }
    return false;
}
